import { useEffect, useState } from "react";

const SIZE = 10;

function point(x, y) {
  return { x, y };
}

function add(a, b) {
  return point(a.x + b.x, a.y + b.y);
}

function equal(a, b) {
  return a.x === b.x && a.y === b.y;
}

function randomFood() {
  return point(
    Math.floor(Math.random() * SIZE),
    Math.floor(Math.random() * SIZE)
  );
}

function emptyBoard() {
  return Array.from(
    { length: SIZE },
    () => Array(SIZE).fill(null)
  );
}

function progress(snake, food, direction) {
  const head = add(snake[0], direction);

  const nextSnake = [
    head,
    ...snake,
  ];

  if (equal(head, food)) {
    return {
      snake: nextSnake,
      food: randomFood(),
    };
  }

  nextSnake.pop();

  return {
    snake: nextSnake,
    food,
  };
}

export default function Snake() {
  const [snake, setSnake] = useState([
    point(5, 5),
  ]);

  const [food, setFood] = useState(
    point(2, 2)
  );

  const [direction, setDirection] = useState(
    point(1, 0)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      const next = progress(
        snake,
        food,
        direction
      );

      setSnake(next.snake);
      setFood(next.food);
    }, 300);

    return () => clearInterval(timer);
  }, [snake, food, direction]);

  function keyDown(e) {
    if (e.key === "ArrowUp") setDirection(point(0, -1));
    if (e.key === "ArrowDown") setDirection(point(0, 1));
    if (e.key === "ArrowLeft") setDirection(point(-1, 0));
    if (e.key === "ArrowRight") setDirection(point(1, 0));
  }

  function createBoard() {
    const board = emptyBoard();

    for (const part of snake) {
      board[part.y][part.x] = "snake";
    }

    board[food.y][food.x] = "food";

    return board;
  }

  const board = createBoard();

  return (
    <main onKeyDown={keyDown} tabIndex={0}>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {board.map((row, y) => (
            <tr key={y}>
              {row.map((cell, x) => (
                <td
                  key={x}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background:
                      cell === "snake"
                        ? "green"
                        : cell === "food"
                        ? "red"
                        : "white",
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
